import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

const TaskManager = () => {
  const { user } = useAuth();
  // Lấy dữ liệu và hàm từ DataContext (đã kết nối Firebase)
  const { 
      tasks, addTask, deleteTask, 
      staffList, disciplineTypes, 
      schedules, addSchedule, deleteSchedule, updateSchedule 
  } = useData();
  
  const isScheduler = user?.role === 'scheduler';
  const activeDisciplines = disciplineTypes ? disciplineTypes.filter(d => d.status === 'Active') : [];

  // --- STATE FORM NHIỆM VỤ (TASK) ---
  const [newTask, setNewTask] = useState({ 
      title: '', assigneeId: '', description: '',
      startTime: '', endTime: '', 
      assignedRole: 'ST',
      paymentType: 'UBI 1', 
      disciplineId: '' 
  });

  // --- STATE FORM LỊCH TRÌNH (SCHEDULE) ---
  const [scheduleForm, setScheduleForm] = useState({
      repeatWeeks: 1,
      selectedDays: [],
      title: '', assigneeId: '', 
      startTimeStr: '08:00', endTimeStr: '17:00', 
      description: ''
  });
  const [editingSchedule, setEditingSchedule] = useState(null);

  const daysOfWeek = [
      { id: 'T2', label: 'Thứ 2' }, { id: 'T3', label: 'Thứ 3' }, { id: 'T4', label: 'Thứ 4' },
      { id: 'T5', label: 'Thứ 5' }, { id: 'T6', label: 'Thứ 6' }, { id: 'T7', label: 'Thứ 7' }, { id: 'CN', label: 'Chủ Nhật' }
  ];

  // --- XỬ LÝ NHIỆM VỤ ---
  const handleAddTask = (e) => {
    e.preventDefault();
    if (!newTask.title || !newTask.assigneeId || !newTask.endTime) return alert("Vui lòng điền đủ thông tin!");
    
    const staff = staffList.find(s => s.id === newTask.assigneeId);
    const disc = activeDisciplines.find(d => d.id === newTask.disciplineId);

    // Gọi hàm addTask của DataContext (sẽ đẩy lên Firebase)
    addTask({ 
        ...newTask, 
        assigneeName: staff ? staff.name : 'Unknown',
        disciplineName: (disc && !isScheduler) ? disc.name : (isScheduler ? 'N/A' : 'Chưa quy định'),
        paymentType: isScheduler ? 'N/A' : newTask.paymentType,
        deadline: newTask.endTime,
        createdBy: user.username // Lưu người tạo
    });
    
    setNewTask({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST', paymentType: 'UBI 1', disciplineId: '' });
    alert("Đã giao việc thành công!");
  };

  const handleDeleteTask = (id) => {
    if (window.confirm("Xóa nhiệm vụ này?")) deleteTask(id);
  };

  // --- XỬ LÝ LỊCH TRÌNH (SCHEDULER) ---
  const handleDayToggle = (dayId) => {
      const current = scheduleForm.selectedDays;
      if (current.includes(dayId)) {
          setScheduleForm({ ...scheduleForm, selectedDays: current.filter(d => d !== dayId) });
      } else {
          setScheduleForm({ ...scheduleForm, selectedDays: [...current, dayId] });
      }
  };

  const handleSaveSchedule = () => {
      if (!scheduleForm.title || !scheduleForm.assigneeId || scheduleForm.selectedDays.length === 0) {
          return alert("Vui lòng nhập Tiêu đề, Người làm và chọn ít nhất 1 ngày!");
      }
      const staff = staffList.find(s => s.id === scheduleForm.assigneeId);
      
      const scheduleData = {
          ...scheduleForm,
          assigneeName: staff ? staff.name : 'Unknown',
          createdBy: user.username,
          updatedAt: new Date().toISOString()
      };

      if (editingSchedule) {
          updateSchedule(editingSchedule, scheduleData); // Cập nhật Firebase
          setEditingSchedule(null);
          alert("Đã cập nhật lịch!");
      } else {
          addSchedule(scheduleData); // Thêm mới vào Firebase
          alert("Đã lưu lịch công tác!");
      }
      
      // Reset form
      setScheduleForm({ repeatWeeks: 1, selectedDays: [], title: '', assigneeId: '', startTimeStr: '08:00', endTimeStr: '17:00', description: '' });
  };

  const startEditSchedule = (s) => {
      setEditingSchedule(s.id);
      setScheduleForm({
          repeatWeeks: s.repeatWeeks || 1, 
          selectedDays: s.selectedDays || [],
          title: s.title, assigneeId: s.assigneeId, 
          startTimeStr: s.startTimeStr, endTimeStr: s.endTimeStr, description: s.description || ''
      });
  };

  return (
    <div style={{ paddingBottom: '20px' }}>
      <h2 style={{ color: '#003366' }}>
          {isScheduler ? 'Điều phối & Lên lịch' : 'Quản lý Nhiệm vụ (Op Admin)'}
      </h2>

      {/* 1. FORM GIAO VIỆC LẺ */}
      <div style={{ background: 'white', padding: '24px', borderRadius: '16px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', marginBottom: '24px' }}>
        <h4 style={{ margin: '0 0 20px 0' }}>Giao nhiệm vụ lẻ {isScheduler ? '' : '& Thiết lập Kỷ luật'}</h4>
        <form onSubmit={handleAddTask} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
          <div style={{ gridColumn: '1 / -1' }}>
             <label style={styles.label}>Tiêu đề công việc</label>
             <input value={newTask.title} onChange={e => setNewTask({...newTask, title: e.target.value})} style={styles.input} required />
          </div>
          <div>
             <label style={styles.label}>Người thực hiện</label>
             <select value={newTask.assigneeId} onChange={e => setNewTask({...newTask, assigneeId: e.target.value})} style={styles.select} required>
                <option value="">-- Chọn nhân sự --</option>
                {staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}
             </select>
          </div>
          <div>
             <label style={styles.label}>Vai trò thực hiện</label>
             <select value={newTask.assignedRole} onChange={e => setNewTask({...newTask, assignedRole: e.target.value})} style={styles.select}>
                {['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}
             </select>
          </div>
          <div>
             <label style={styles.label}>Bắt đầu (Check-in)</label>
             <input type="datetime-local" value={newTask.startTime} onChange={e => setNewTask({...newTask, startTime: e.target.value})} style={styles.input} required />
          </div>
          <div>
             <label style={styles.label}>Kết thúc (Check-out)</label>
             <input type="datetime-local" value={newTask.endTime} onChange={e => setNewTask({...newTask, endTime: e.target.value})} style={styles.input} required />
          </div>

          {!isScheduler && (
              <>
                <div>
                    <label style={styles.label}>Loại chi trả</label>
                    <select value={newTask.paymentType} onChange={e => setNewTask({...newTask, paymentType: e.target.value})} style={styles.select}>
                        <option value="UBI 1">UBI 1</option>
                        <option value="UBI 2">UBI 2</option>
                        <option value="Remuneration">Remuneration</option>
                    </select>
                </div>
                <div>
                    <label style={styles.label}>Kỷ luật (nếu trễ)</label>
                    <select value={newTask.disciplineId} onChange={e => setNewTask({...newTask, disciplineId: e.target.value})} style={{...styles.select, borderColor: 'red', color: '#b91c1c'}}>
                        <option value="">-- Chọn hình thức (Đã duyệt) --</option>
                        {activeDisciplines.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                    </select>
                </div>
              </>
          )}

          <div style={{ gridColumn: '1 / -1' }}>
             <label style={styles.label}>Mô tả chi tiết</label>
             <textarea value={newTask.description} onChange={e => setNewTask({...newTask, description: e.target.value})} style={{...styles.input, height: '80px'}} />
          </div>

          <button type="submit" style={styles.btnSubmit}>Giao việc</button>
        </form>
      </div>

      {/* 2. FORM LÊN LỊCH (CHỈ SCHEDULER) */}
      {isScheduler && (
          <div style={{ background: '#f0f9ff', padding: '24px', borderRadius: '16px', border: '1px solid #bae6fd', marginBottom: '24px' }}>
              <h4 style={{ margin: '0 0 15px 0', color: '#0284c7' }}>📅 Lên lịch công tác (Định kỳ)</h4>
              
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '15px' }}>
                  <div style={{ gridColumn: '1 / -1' }}>
                      <label style={styles.label}>Tên lịch trình</label>
                      <input value={scheduleForm.title} onChange={e => setScheduleForm({...scheduleForm, title: e.target.value})} style={styles.input} placeholder="Vd: Trực quầy lễ tân" />
                  </div>
                  <div>
                      <label style={styles.label}>Nhân sự</label>
                      <select value={scheduleForm.assigneeId} onChange={e => setScheduleForm({...scheduleForm, assigneeId: e.target.value})} style={styles.select}>
                          <option value="">-- Chọn nhân sự --</option>
                          {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                      </select>
                  </div>
                  <div>
                      <label style={styles.label}>Lặp lại trong (tuần)</label>
                      <input type="number" min="1" value={scheduleForm.repeatWeeks} onChange={e => setScheduleForm({...scheduleForm, repeatWeeks: Number(e.target.value)})} style={styles.input} />
                  </div>
                  <div>
                       <label style={styles.label}>Giờ bắt đầu</label>
                       <input type="time" value={scheduleForm.startTimeStr} onChange={e => setScheduleForm({...scheduleForm, startTimeStr: e.target.value})} style={styles.input} />
                  </div>
                  <div>
                       <label style={styles.label}>Giờ kết thúc</label>
                       <input type="time" value={scheduleForm.endTimeStr} onChange={e => setScheduleForm({...scheduleForm, endTimeStr: e.target.value})} style={styles.input} />
                  </div>
              </div>

              <div style={{ marginBottom: '20px' }}>
                  <label style={styles.label}>Chọn ngày trong tuần:</label>
                  <div style={{ display: 'flex', gap: '10px', marginTop: '8px', flexWrap: 'wrap' }}>
                      {daysOfWeek.map(day => (
                          <label key={day.id} style={{ 
                              padding: '6px 12px', borderRadius: '20px', border: '1px solid #0284c7', 
                              background: scheduleForm.selectedDays.includes(day.id) ? '#0284c7' : 'white',
                              color: scheduleForm.selectedDays.includes(day.id) ? 'white' : '#0284c7',
                              cursor: 'pointer', fontSize: '0.9rem', fontWeight: '500'
                          }}>
                              <input type="checkbox" style={{display:'none'}} checked={scheduleForm.selectedDays.includes(day.id)} onChange={() => handleDayToggle(day.id)} />
                              {day.label}
                          </label>
                      ))}
                  </div>
              </div>

              <div style={{display:'flex', gap: '10px'}}>
                <button onClick={handleSaveSchedule} style={{...styles.btnSubmit, background: '#0284c7', gridColumn: 'unset', width: 'auto', padding: '10px 30px'}}>
                    {editingSchedule ? 'Cập nhật Lịch' : 'Lưu Lịch'}
                </button>
                {editingSchedule && (
                    <button onClick={() => { setEditingSchedule(null); setScheduleForm({ repeatWeeks: 1, selectedDays: [], title: '', assigneeId: '', startTimeStr: '08:00', endTimeStr: '17:00', description: '' }) }} style={{...styles.btnSubmit, background: '#94a3b8', gridColumn: 'unset', width: 'auto'}}>Hủy</button>
                )}
              </div>
          </div>
      )}

      {/* 3. DANH SÁCH LỊCH ĐÃ THIẾT LẬP (SCHEDULER) */}
      {isScheduler && (
          <div style={{ background: 'white', padding: '20px', borderRadius: '16px', marginBottom: '24px', border: '1px solid #e2e8f0' }}>
             <h4 style={{color: '#334155'}}>Danh sách lịch đã thiết lập</h4>
             {(!schedules || schedules.length === 0) ? <p style={{fontStyle:'italic', color:'#94a3b8'}}>Chưa có lịch nào.</p> : (
                 <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
                    <thead>
                       <tr style={{textAlign:'left', borderBottom: '1px solid #eee', color: '#64748b'}}>
                         <th style={{padding:'10px'}}>Tên lịch</th>
                         <th>Người làm</th>
                         <th>Lặp (Tuần)</th>
                         <th>Ngày & Giờ</th>
                         <th>Thao tác</th>
                       </tr>
                    </thead>
                    <tbody>
                       {schedules.map(s => (
                         <tr key={s.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                            <td style={{padding:'10px', fontWeight:'600', color:'#334155'}}>{s.title}</td>
                            <td>{s.assigneeName}</td>
                            <td>{s.repeatWeeks}</td>
                            <td>
                                <div>{s.selectedDays ? s.selectedDays.join(', ') : ''}</div>
                                <div style={{fontSize:'0.8rem', color:'#64748b'}}>{s.startTimeStr} - {s.endTimeStr}</div>
                            </td>
                            <td>
                                <button onClick={()=>startEditSchedule(s)} style={{color:'#0284c7', marginRight:'10px', border:'none', background:'none', cursor:'pointer', fontWeight:'bold'}}>Điều chỉnh</button>
                                <button onClick={()=>{ if(window.confirm('Xóa lịch này?')) deleteSchedule(s.id) }} style={{color:'#ef4444', border:'none', background:'none', cursor:'pointer'}}>Xóa</button>
                            </td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
             )}
          </div>
      )}

      {/* 4. DANH SÁCH NHIỆM VỤ ĐANG CHẠY */}
      <div style={{ background: 'white', padding: '20px', borderRadius: '16px' }}>
         <h4>Danh sách nhiệm vụ thực tế</h4>
         <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
            <thead>
               <tr style={{textAlign:'left', borderBottom: '1px solid #eee'}}>
                 <th style={{padding:'10px'}}>Nhiệm vụ</th>
                 <th>Người làm</th>
                 {!isScheduler && <th>Kỷ luật</th>}
                 <th>Hạn chót</th>
                 <th>Tiến độ</th>
                 <th>Xóa</th>
               </tr>
            </thead>
            <tbody>
               {tasks.map(t => (
                 <tr key={t.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                    <td style={{padding:'10px'}}>
                        <strong>{t.title}</strong><br/>
                        {!isScheduler && <span style={{fontSize:'0.75rem', color:'#666'}}>{t.paymentType}</span>}
                    </td>
                    <td>{t.assigneeName}</td>
                    {!isScheduler && <td>{t.disciplineName}</td>}
                    <td>{t.endTime ? new Date(t.endTime).toLocaleString() : 'N/A'}</td>
                    <td>{t.progress}%</td>
                    <td><button onClick={()=>handleDeleteTask(t.id)} style={{color:'red', border:'none', background:'none', cursor:'pointer'}}>Xóa</button></td>
                 </tr>
               ))}
            </tbody>
         </table>
      </div>
    </div>
  );
};

const styles = {
    input: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', boxSizing: 'border-box' },
    select: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', background: 'white' },
    label: { fontSize: '0.8rem', fontWeight: 'bold', color: '#555' },
    btnSubmit: { gridColumn: '1 / -1', padding: '12px', background: '#003366', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' }
};

export default TaskManager;
